            clothingSecondaryColor: lastAppliedPalette ? lastAppliedPalette.colors[1] : prev.clothingSecondaryColor,
        }));

    } catch (error) {
        console.error("Randomize failed:", error);
        setErrorMsg("随机生成失败，请重试。");
        setState(prev => ({ ...prev, isGenerating: false }));
    }
