                                >
                                    ✨ 生成 4 宫格预览图
                                </button>
                            </div>

                            {/* Added Blueprint Button Here since Result page is gone */}
                            <div className="mt-6 border-t pt-6 text-center">
                                <button 
                                    onClick={handleBlueprintRender}
                                    disabled={state.isGenerating}
                                    className="w-full bg-blue-50 hover:bg-blue-100 text-blue-700 font-bold py-3 px-6 rounded-full shadow transition-transform transform hover:scale-105 flex items-center justify-center gap-2 border border-blue-200"
