      customAppearanceWeight: 50,
      customClothingImg: null,
      customClothingWeight: 50,
      customActionImg: null,
      customActionWeight: 50,
      customTextPrompt: ""
    }));
    // Trigger image reload for default gender
    updateBaseCharacter(Gender.Male, AgeGroup.Primary);
