        imgIndex++;
    }
    if (actionRef) {
        fullPrompt += `- Image ${imgIndex}: ACTION/POSE Reference. Influence: ${actionWeight}%.\n`;
        imgIndex++;
    }

    fullPrompt += `
    USER INSTRUCTIONS:
    "${promptText}"

    CRITICAL FRAMING INSTRUCTIONS (MUST FOLLOW):
    1. OUTPUT FORMAT: 2x2 Grid inside a 1:1 SQUARE Image.
    2. FRAMING SOURCE: STRICTLY COPY the framing/zoom level of Image 1 (Base Character).
    3. IGNORE REFERENCE FRAMING: Do NOT use the framing, camera angle, or body proportions of the reference images (Hairstyle/Clothing/Action refs). Even if a reference image shows a full body, you must ONLY generate a WAIST-UP / HALF-BODY portrait matching Image 1.
    4. CROP: Waist-up / Half-body. Head and shoulders must be clearly visible.
    5. NO FULL BODY. Do NOT show legs or feet. 

    CRITICAL STYLE & QUALITY INSTRUCTIONS:
    1. RENDER QUALITY: Ultra-High Definition, 8k, Completely Denoised.
    2. MATERIAL: Smooth, soft matte plastic or high-quality vinyl (Art Toy / Blind Box style).
    3. NEGATIVE CONSTRAINTS: NO noise, NO film grain, NO dithering, NO jpeg artifacts, NO realistic skin texture, NO messy details.
    4. LIGHTING: Soft studio lighting, ambient occlusion, clean shadows, pure white background (#FFFFFF).
    `;

    // 3. Construct Payload
    parts.push({ text: fullPrompt });
    parts.push({ inlineData: { mimeType: 'image/png', data: baseImage }}); // Image 1

    if (appearanceRef) {
        parts.push({ inlineData: { mimeType: 'image/png', data: appearanceRef }}); 
    }
    if (clothingRef) {
        parts.push({ inlineData: { mimeType: 'image/png', data: clothingRef }});
    }
    if (actionRef) {
        parts.push({ inlineData: { mimeType: 'image/png', data: actionRef }});
    }

    const makeRequest = async (attempt = 1): Promise<string> => {
        try {
            const response = await ai.models.generateContent({
                model: MODEL_NAME,
                contents: { parts },
                config: {
                    // Grid images maintained at 2K as requested
                    imageConfig: { imageSize: '2K', aspectRatio: '1:1' }
                }
            });

            const respParts = response.candidates?.[0]?.content?.parts;
            const imagePart = respParts?.find(part => part.inlineData && part.inlineData.data);

            if (imagePart && imagePart.inlineData) {
                return imagePart.inlineData.data;
            }
            throw new Error("No image generated.");

        } catch (error: any) {
             // Retry for 500 errors or network issues
            const isNetworkError = error.status === 500 || error.message?.includes('xhr') || error.message?.includes('fetch') || error.message?.includes('network');

            if (attempt < 3 && isNetworkError) {
                console.warn(`Custom Grid Gen failed (Attempt ${attempt}). Retrying in ${2 * attempt}s...`, error);
                await new Promise(r => setTimeout(r, 2000 * attempt)); // Exponential backoff
                return makeRequest(attempt + 1);
            }
            console.error("Custom Grid Generation Error:", error);
            throw error;
        }
    };

    return await makeRequest();
};

