    `;

    const makeRequest = async (attempt = 1): Promise<string> => {
        try {
            const response = await ai.models.generateContent({
                model: MODEL_NAME,
                contents: {
                parts: [
                    { text: prompt },
                    { inlineData: { mimeType: 'image/png', data: base64Image } }
                ],
                },
                config: {
                    // Grid images maintained at 2K as requested
                    imageConfig: { imageSize: '2K', aspectRatio: '1:1' }
                }
            });

            const parts = response.candidates?.[0]?.content?.parts;
            const imagePart = parts?.find(part => part.inlineData && part.inlineData.data);

            if (imagePart && imagePart.inlineData) {
                return imagePart.inlineData.data;
            }
            throw new Error("No image generated.");
        } catch (error: any) {
             // Retry for 500 errors or network issues
             const isNetworkError = error.status === 500 || error.message?.includes('xhr') || error.message?.includes('fetch') || error.message?.includes('network');

             if (attempt < 3 && isNetworkError) {
                 console.warn(`Random Grid Gen failed (Attempt ${attempt}). Retrying in ${2 * attempt}s...`, error);
                 await new Promise(r => setTimeout(r, 2000 * attempt)); // Exponential backoff
                 return makeRequest(attempt + 1);
             }
             console.error("Random Grid Generation Error:", error);
             throw error;
        }
    };

    return await makeRequest();
};

