import { GoogleGenAI } from "@google/genai";

// Initialize the client
// The API key MUST be in process.env.API_KEY
// Note: For gemini-3-pro-image-preview, key selection is handled in App.tsx via aistudio.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = 'gemini-3-pro-image-preview';

const MAX_RETRIES = 5;

const calculateDelay = (attempt: number) => {
  // Exponential backoff: 2s, 4s, 8s, 16s, 32s + random jitter
  return Math.pow(2, attempt) * 1000 + Math.floor(Math.random() * 1000);
};

const isRetryableError = (error: any): boolean => {
  return (
    error.status === 503 || 
    error.status === 500 || 
    error.status === 429 ||
    (error.message && (
        error.message.includes('overloaded') ||
        error.message.includes('UNAVAILABLE') ||
        error.message.includes('503') ||
        error.message.includes('xhr') || 
        error.message.includes('fetch') || 
        error.message.includes('network')
    ))
  );
};

